/*
  # Seed Build sidebar groups and pages

  Creates 7 sidebar groups with ~52 child topic pages for the
  Build section. Technical reference organized by developer task
  sequence: architecture, schemas, building, deploying, observability,
  design governance, and contributing.
*/

DO $$
DECLARE
  v_section_id uuid;
  v_group_id uuid;
BEGIN
  SELECT id INTO v_section_id FROM nav_sections WHERE slug = 'build';

  -- Group 1: Architecture
  VALUES (v_section_id, 'Architecture', 'architecture', 1)
  RETURNING id INTO v_group_id;


  -- Group 2: Schemas and APIs
  VALUES (v_section_id, 'Schemas and APIs', 'schemas-and-apis', 2)
  RETURNING id INTO v_group_id;


  -- Group 3: Building a Vertical Application
  VALUES (v_section_id, 'Building a Vertical Application', 'building-a-vertical-application', 3)
  RETURNING id INTO v_group_id;


  -- Group 4: Deployment and Operations
  VALUES (v_section_id, 'Deployment and Operations', 'deployment-and-operations', 4)
  RETURNING id INTO v_group_id;


  -- Group 5: Observability and Maintenance
  VALUES (v_section_id, 'Observability and Maintenance', 'observability-and-maintenance', 5)
  RETURNING id INTO v_group_id;


  -- Group 6: Wayfinder for Developers
  VALUES (v_section_id, 'Wayfinder for Developers', 'wayfinder-for-developers', 6)
  RETURNING id INTO v_group_id;


  -- Group 7: Contributing to the Codebase
  VALUES (v_section_id, 'Contributing to the Codebase', 'contributing-to-the-codebase', 7)
  RETURNING id INTO v_group_id;


END $$;
